168→/// User-provided mock override from `.shatter/config.yaml`.
169→#[derive(Debug, Clone, PartialEq, serde::Deserialize, serde::Serialize)]
170→pub struct MockOverride {
171→    /// Pre-configured return values, replacing auto-generated defaults.
172→    #[serde(default)]
173→    pub return_values: Option<Vec<Value>>,
174→    /// Override the default behavior.
175→    #[serde(default)]
176→    pub behavior: Option<MockBehavior>,
177→}
178→
179→/// Generate auto-mocks for all dependencies of a function.
180→///
181→/// Returns mock configs for dependencies that:
182→/// 1. Are not already covered by `existing_mocks` (e.g., behavior-map mocks)
183→/// 2. Are classified as Mock (not Passthrough or Analyze) by the scope matcher
184→///
185→/// User overrides from config take precedence over auto-generated defaults.
186→pub fn generate_auto_mocks(
187→    deps: &[ExternalDependency],
188→    scope: Option<&ScopeMatcher>,
189→    overrides: &HashMap<String, MockOverride>,
190→    existing_mocks: &[MockConfig],
191→) -> Vec<MockConfig> {
192→    let already_mocked: std::collections::HashSet<&str> = existing_mocks
193→        .iter()
194→        .map(|m| m.symbol.as_str())
195→        .collect();
196→
197→    let mut result = Vec::new();
198→
199→    for dep in deps {
200→        // Skip if already covered by a behavior-map mock
201→        if already_mocked.contains(dep.symbol.as_str()) {
202→            continue;
203→        }
204→
205→        // Check scope: if Passthrough, skip; if Analyze (no rule), use category logic
206→        if let Some(matcher) = scope {
207→            match matcher.classify_dependency(&dep.symbol) {
208→                DependencyAction::Passthrough => continue,
209→                DependencyAction::Mock | DependencyAction::Analyze => {}
210→            }
211→        }
212→
213→        let category = classify_dependency(dep);
214→
215→        // Pure utilities default to passthrough — skip generating a mock
216→        if category == IoCategory::PureUtility && !overrides.contains_key(&dep.symbol) {
217→            continue;
218→        }
219→
220→        let mut mock = generate_default_mock(dep, category);
221→
222→        // Apply user overrides
223→        if let Some(ov) = overrides.get(&dep.symbol) {
224→            if let Some(ref vals) = ov.return_values {
225→                mock.return_values = vals.clone();
226→            }
227→            if let Some(ref behavior) = ov.behavior {
228→                mock.default_behavior = behavior.clone();
229→            }
230→        }
231→
232→        result.push(mock);
233→    }
234→
235→    result
236→}
237→
238→/// Where a mock's return value originated.
239→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
240→pub enum ValueSource {
241→    /// Generated automatically from dependency classification and type info.
242→    AutoGenerated,
243→    /// Overridden by the user via `.shatter/config.yaml`.
244→    UserOverride,
245→    /// Inherited from an existing behavior-map mock.
246→    BehaviorMap,
247→}
248→
249→/// A resolved mock parameter ready for the orchestrator, combining dependency
250→/// metadata with its mock configuration.
251→#[derive(Debug, Clone, PartialEq)]
252→pub struct MockParam {
253→    /// Fully qualified symbol name of the mocked dependency.
254→    pub symbol: String,
255→    /// Return type of the dependency (used for value generation).
256→    pub return_type: TypeInfo,
257→    /// Classified I/O category.
258→    pub category: IoCategory,
259→    /// Estimated number of calls based on static call-site count.
260→    pub call_count_estimate: u32,
261→    /// Where the mock's return value came from.
262→    pub value_source: ValueSource,
263→}
264→
265→/// Build [`MockParam`]s from dependencies and their resolved mock configs.
266→///
267→/// Filters out dependencies whose category is [`IoCategory::PureUtility`]
268→/// unless a matching config explicitly overrides them. Dependencies with
269→/// a matching config get [`ValueSource::UserOverride`]; those without get
270→/// [`ValueSource::AutoGenerated`].
271→pub fn build_mock_params(
272→    deps: &[ExternalDependency],
273→    configs: &[MockConfig],
274→) -> Vec<MockParam> {
275→    let config_by_symbol: HashMap<&str, &MockConfig> = configs
276→        .iter()
277→        .map(|c| (c.symbol.as_str(), c))
278→        .collect();
279→
280→    let mut result = Vec::new();
281→
282→    for dep in deps {
283→        let category = classify_dependency(dep);
284→        let has_config = config_by_symbol.contains_key(dep.symbol.as_str());
285→
286→        // Pure utilities are passthrough unless explicitly configured
287→        if category == IoCategory::PureUtility && !has_config {
288→            continue;
289→        }
290→
291→        let value_source = if has_config {
292→            ValueSource::UserOverride
293→        } else {
294→            ValueSource::AutoGenerated
295→        };
296→
297→        result.push(MockParam {
298→            symbol: dep.symbol.clone(),
299→            return_type: dep.return_type.clone(),

300→            // Random date between 1970 and 2030
301→            rng.random_range(0..1_893_456_000_000_i64)
302→        }
303→    };
304→    json!({"__complex_type": "date", "value": epoch_ms})
305→}
306→
307→/// Generate a Duration value as `{"__complex_type": "duration", "ms": <millis>}`.
308→fn generate_duration(rng: &mut impl Rng) -> Value {
309→    let choice: u8 = rng.random_range(0..10);
310→    let ms: i64 = match choice {
311→        0 => 0,                        // Zero duration
312→        1 => -1,                       // Negative
313→        2 => 1,                        // 1ms
314→        3 => 1_000,                    // 1 second
315→        4 => 60_000,                   // 1 minute
316→        5 => 3_600_000,               // 1 hour
317→        6 => 86_400_000,              // 1 day
318→        7 => -86_400_000,             // Negative 1 day
319→        8 => 9_007_199_254_740_991,   // MAX_SAFE_INTEGER
320→        _ => rng.random_range(-86_400_000..=86_400_000),
321→    };
322→    json!({"__complex_type": "duration", "ms": ms})
323→}
324→
325→/// Generate a Time value as `{"__complex_type": "time", "hour": h, "minute": m, "second": s, "ms": ms}`.
326→fn generate_time(rng: &mut impl Rng) -> Value {
327→    let choice: u8 = rng.random_range(0..6);
328→    let (h, m, s, ms) = match choice {
329→        0 => (0, 0, 0, 0),           // Midnight
330→        1 => (12, 0, 0, 0),          // Noon
331→        2 => (23, 59, 59, 999),      // End of day
332→        3 => (0, 0, 1, 0),           // Just after midnight
333→        _ => (
334→            rng.random_range(0..24) as u8,
335→            rng.random_range(0..60) as u8,
336→            rng.random_range(0..60) as u8,
337→            rng.random_range(0..1000) as u16,
338→        ),
339→    };
340→    json!({"__complex_type": "time", "hour": h, "minute": m, "second": s, "ms": ms})
341→}
342→
343→/// Generate a RegExp value.
344→fn generate_regexp(rng: &mut impl Rng) -> Value {
345→    let patterns = [
346→        (".*", ""), ("\\d+", "g"), ("[a-z]+", "i"), ("^\\s+$", ""),
347→        ("\\w{3,}", "gi"), ("^$", ""), (".", ""), ("\\d{3}-\\d{4}", ""),
348→    ];
349→    let idx = rng.random_range(0..patterns.len());
350→    let (source, flags) = patterns[idx];
351→    json!({"__complex_type": "reg_exp", "source": source, "flags": flags})
352→}
353→
354→/// Generate a URL value.
355→fn generate_url(rng: &mut impl Rng) -> Value {
356→    let urls = [
357→        "https://example.com",
358→        "https://example.com/path?q=1",
359→        "http://localhost:3000",
360→        "https://example.com:8443/api/v1",
361→        "https://example.com/path#fragment",
362→        "https://user:pass@example.com",
363→        "ftp://files.example.com/pub",
364→        "https://xn--r8jz45g.jp/%E3%83%86%E3%82%B9%E3%83%88",
365→    ];
366→    let idx = rng.random_range(0..urls.len());
367→    json!({"__complex_type": "url", "value": urls[idx]})
368→}
369→
370→/// Generate an Error value.
371→fn generate_error(
372→    metadata: &serde_json::Map<String, serde_json::Value>,
373→    rng: &mut impl Rng,
374→) -> Value {
375→    let class = metadata
376→        .get("class")
377→        .and_then(|c| c.as_str())
378→        .unwrap_or_else(|| {
379→            let classes = ["Error", "TypeError", "RangeError", "SyntaxError"];
380→            classes[rng.random_range(0..classes.len())]
381→        });
382→    let messages = ["", "oops", "invalid argument", "out of range", "unexpected token"];
383→    let msg = messages[rng.random_range(0..messages.len())];
384→    json!({"__complex_type": "error", "class": class, "message": msg})
385→}
386→
387→/// Generate a BigInt value.
388→fn generate_bigint(rng: &mut impl Rng) -> Value {
389→    let choice: u8 = rng.random_range(0..8);
390→    let s = match choice {
391→        0 => "0".to_string(),
392→        1 => "1".to_string(),
393→        2 => "-1".to_string(),
394→        3 => "9007199254740992".to_string(), // MAX_SAFE_INTEGER + 1
395→        4 => "-9007199254740992".to_string(),
396→        5 => "99999999999999999999999999999999".to_string(), // 32 digits
397→        _ => {
398→            let digits = rng.random_range(1..=20);
399→            let neg = rng.random_bool(0.3);
400→            let mut s = if neg { "-".to_string() } else { String::new() };
401→            for i in 0..digits {
402→                let d = if i == 0 { rng.random_range(1..=9) } else { rng.random_range(0..=9) };
403→                s.push(char::from(b'0' + d as u8));
404→            }
405→            s
406→        }
407→    };
408→    json!({"__complex_type": "big_int", "value": s})
409→}
410→
411→/// Generate a BigDecimal value.
412→fn generate_big_decimal(rng: &mut impl Rng) -> Value {
413→    let vals = ["0", "0.01", "-0.01", "3.14159265358979323846", "1000000.000001"];
414→    let idx = rng.random_range(0..vals.len());
415→    json!({"__complex_type": "big_decimal", "value": vals[idx]})
416→}
417→
418→/// Generate a UUID value.
419→fn generate_uuid(rng: &mut impl Rng) -> Value {
420→    let choice: u8 = rng.random_range(0..4);
421→    let uuid = match choice {
422→        0 => "00000000-0000-0000-0000-000000000000".to_string(), // nil
423→        1 => "ffffffff-ffff-ffff-ffff-ffffffffffff".to_string(), // all ones
424→        _ => {
425→            // Random v4 UUID
426→            let bytes: Vec<String> = (0..16)
427→                .map(|_| format!("{:02x}", rng.random_range(0u8..=255)))
428→                .collect();
429→            format!(
430→                "{}-{}-4{}-{}{}-{}",
431→                bytes[0..4].join(""),
432→                bytes[4..6].join(""),
433→                &bytes[6][1..],
434→                &["8", "9", "a", "b"][rng.random_range(0..4)],
435→                &bytes[7][1..],
436→                bytes[8..14].join(""),
437→            )
438→        }
439→    };
440→    json!({"__complex_type": "uuid", "value": uuid})
441→}
442→
443→/// Generate an IP address value.
444→fn generate_ip_address(rng: &mut impl Rng) -> Value {
445→    let choice: u8 = rng.random_range(0..6);
446→    let (version, value) = match choice {
