711→/// Generate a complete set of random inputs for a function's parameters.
712→///
713→/// When `caps` is provided, complex types are only generated if the frontend
714→/// declared support; otherwise they fall back to unknown/primitive generation.
715→pub fn generate_random_inputs(
716→    params: &[crate::types::ParamInfo],
717→    rng: &mut impl Rng,
718→    caps: Option<&FrontendCapabilities>,
719→) -> Vec<Value> {
720→    params
721→        .iter()
722→        .map(|p| {
723→            if matches!(p.typ, TypeInfo::Str) {
724→                let hint = heuristic_string_for_name(&p.name)
725→                    .or_else(|| p.type_name.as_deref().and_then(heuristic_string_for_name));
726→                if let Some(val) = hint {
727→                    return json!(val);
728→                }
729→            }
730→            generate_random_value(&p.typ, rng, caps)
731→        })
732→        .collect()
733→}
