840→/// A single value produced by a custom generator, with replay metadata.
841→#[derive(Debug, Clone)]
842→pub struct GeneratedEntry {
843→    /// The generated value (JSON).
844→    pub value: Value,
845→    /// Human-readable label from the generator.
846→    pub generator_id: String,
847→    /// Serializable recipe for replaying this generation.
848→    /// For WASM generators where value IS the recipe, this is `None`.
849→    pub recipe: Option<Value>,
850→    /// Composite ID: `"{generator_id}@{recipe_hash}"`.
851→    pub composite_id: String,
852→}
853→
854→/// Pre-fetched values from custom generators, keyed by `(generator_file, generator_name)`.
855→///
856→/// Each entry holds a queue of generated entries that can be drawn from during
857→/// input generation. When the queue is empty, generation falls back to built-in.
858→#[derive(Debug, Default)]
859→pub struct PrefetchedValues {
860→    /// Map from (generator file path as string, generator name) to queued entries.
861→    entries: std::collections::HashMap<(String, String), Vec<GeneratedEntry>>,
862→}
863→
864→impl PrefetchedValues {
865→    /// Create an empty prefetch store.
866→    #[must_use]
867→    pub fn new() -> Self {
868→        Self {
869→            entries: std::collections::HashMap::new(),
870→        }
871→    }
872→
873→    /// Insert generated values for a specific generator (legacy API, no metadata).
874→    pub fn insert(&mut self, file: String, name: String, vals: Vec<Value>) {
875→        let entries: Vec<GeneratedEntry> = vals
876→            .into_iter()
877→            .map(|v| {
878→                let composite = crate::canonical_json::composite_id("unknown", &v);
879→                GeneratedEntry {
880→                    value: v,
881→                    generator_id: "unknown".into(),
882→                    recipe: None,
883→                    composite_id: composite,
884→                }
885→            })
886→            .collect();
887→        self.entries.entry((file, name)).or_default().extend(entries);
888→    }
889→
890→    /// Insert a fully-formed generated entry with metadata.
891→    pub fn insert_entry(&mut self, file: String, name: String, entry: GeneratedEntry) {
892→        self.entries.entry((file, name)).or_default().push(entry);
893→    }
894→
895→    /// Take the next value for a generator, if available.
896→    pub fn take(&mut self, file: &str, name: &str) -> Option<Value> {
897→        self.take_entry(file, name).map(|e| e.value)
898→    }
899→

 900→    /// Take the next entry (value + metadata) for a generator, if available.
 901→    pub fn take_entry(&mut self, file: &str, name: &str) -> Option<GeneratedEntry> {
 902→        let key = (file.to_string(), name.to_string());
 903→        let queue = self.entries.get_mut(&key)?;
 904→        if queue.is_empty() {
 905→            None
 906→        } else {
 907→            Some(queue.remove(0))
 908→        }
 909→    }
 910→
 911→    /// Check whether a generator has remaining values.
 912→    #[must_use]
 913→    pub fn has_values(&self, file: &str, name: &str) -> bool {
 914→        self.entries
 915→            .get(&(file.to_string(), name.to_string()))
 916→            .is_some_and(|q| !q.is_empty())
 917→    }
 918→}
 919→
 920→/// Collect the set of unique Generate commands needed for the given value sources.
 921→///
 922→/// Returns `(file, name, kind)` tuples suitable for building protocol `Generate` commands.
 923→/// De-duplicates so each generator is only invoked once per prefetch round.
 924→pub fn collect_generate_commands(
 925→    sources: &[ValueSource],
 926→) -> Vec<(String, String, crate::protocol::GeneratorKind)> {
 927→    let mut seen = std::collections::HashSet::new();
 928→    let mut commands = Vec::new();
 929→    for source in sources {
 930→        if let ValueSource::CustomGenerator {
 931→            generator_name,
 932→            generator_file,
 933→            kind,
 934→            ..
 935→        } = source
 936→        {
 937→            let key = (generator_file.display().to_string(), generator_name.clone());
 938→            if seen.insert(key.clone()) {
 939→                commands.push((key.0, key.1, kind.clone()));
 940→            }
 941→        }
 942→    }
 943→    commands
 944→}
 945→
 946→/// Batch-prefetch values from custom generators via the frontend protocol.
 947→///
 948→/// Sends `Generate` commands for each unique generator and stores the returned
 949→/// values in a `PrefetchedValues` store. Each generator is called `count` times.
 950→///
 951→/// Returns an error if any protocol send/receive fails.
 952→pub async fn prefetch_custom_values(
 953→    sources: &[ValueSource],
 954→    frontend: &mut crate::frontend::Frontend,
 955→    count: usize,
 956→) -> Result<PrefetchedValues, crate::frontend::FrontendError> {
 957→    let commands = collect_generate_commands(sources);
 958→    let mut store = PrefetchedValues::new();
 959→
 960→    for (file, name, kind) in &commands {
 961→        for _ in 0..count {
 962→            let response = frontend
 963→                .send(crate::protocol::Command::Generate {
 964→                    file: file.clone(),
 965→                    name: name.clone(),
 966→                    kind: kind.clone(),
 967→                    recipe: None,
 968→                    project_root: None,
 969→                })
 970→                .await?;
 971→
 972→            match response.result {
 973→                crate::protocol::ResponseResult::Generate { value, generator_id, recipe } => {
 974→                    let effective_recipe = recipe.as_ref().unwrap_or(&value);
 975→                    let composite = crate::canonical_json::composite_id(&generator_id, effective_recipe);
 976→                    store.insert_entry(file.clone(), name.clone(), GeneratedEntry {
 977→                        value,
 978→                        generator_id,
 979→                        recipe,
 980→                        composite_id: composite,
 981→                    });
 982→                }
 983→                crate::protocol::ResponseResult::Error { message, .. } => {
 984→                    // Log but don't fail -- we'll fall back to built-in generation.
 985→                    log::warn!("generator error for {name} ({file}): {message}");
 986→                }
 987→                _ => {
 988→                    // Unexpected response type -- skip this generator.
 989→                    log::warn!("unexpected response for generator {name}");
 990→                }
 991→            }
 992→        }
 993→    }
 994→
 995→    Ok(store)
 996→}
