1046→// ---------------------------------------------------------------------------
1047→// Type-aware mutation operators
1048→// ---------------------------------------------------------------------------
1049→
1050→/// Mutate a single JSON value according to its type.
1051→///
1052→/// Applies a random type-appropriate mutation operator. The output is always
1053→/// type-valid for the given `TypeInfo`. Types that cannot be meaningfully
1054→/// mutated (Complex, Opaque, Unknown) are returned unchanged.
1055→pub fn mutate_value(value: &Value, typ: &TypeInfo, dictionary: &[&str], rng: &mut impl Rng) -> Value {
1056→    match typ {
1057→        TypeInfo::Int => mutate_int(value, rng),
1058→        TypeInfo::Float => mutate_float(value, rng),
1059→        TypeInfo::Bool => mutate_bool(value),
1060→        TypeInfo::Str => mutate_string(value, dictionary, rng),
1061→        TypeInfo::Array { element } => mutate_array(value, element, dictionary, rng),
1062→        TypeInfo::Object { fields } => mutate_object(value, fields, dictionary, rng),
1063→        TypeInfo::Union { variants } => mutate_union(value, variants, dictionary, rng),
1064→        TypeInfo::Nullable { inner } => mutate_nullable(value, inner, dictionary, rng),
1065→        TypeInfo::Complex { .. } | TypeInfo::Opaque { .. } | TypeInfo::Unknown => value.clone(),
1066→    }
1067→}
1068→
1069→/// Mutate an input vector with per-field probability.
1070→///
1071→/// For each parameter, with probability `mutation_rate` (0.0–1.0), applies
1072→/// `mutate_value`; otherwise keeps the original value unchanged.
1073→pub fn mutate_inputs(
1074→    inputs: &[Value],
1075→    params: &[crate::types::ParamInfo],
1076→    mutation_rate: f64,
1077→    dictionary: &[&str],
1078→    rng: &mut impl Rng,
1079→) -> Vec<Value> {
1080→    inputs
1081→        .iter()
1082→        .zip(params.iter())
1083→        .map(|(val, param)| {
1084→            if rng.random_range(0.0..1.0_f64) < mutation_rate {
1085→                mutate_value(val, &param.typ, dictionary, rng)
1086→            } else {
1087→                val.clone()
1088→            }
1089→        })
1090→        .collect()
1091→}
1092→
1093→/// Mutate an integer value.
1094→fn mutate_int(value: &Value, rng: &mut impl Rng) -> Value {
1095→    let n = match value.as_i64() {
1096→        Some(n) => n,
1097→        None => return generate_int(rng),
1098→    };
1099→    let op: u8 = rng.random_range(0..3);

250→/// metadata with its mock configuration.
251→#[derive(Debug, Clone, PartialEq)]
252→pub struct MockParam {
253→    /// Fully qualified symbol name of the mocked dependency.
254→    pub symbol: String,
255→    /// Return type of the dependency (used for value generation).
256→    pub return_type: TypeInfo,
257→    /// Classified I/O category.
258→    pub category: IoCategory,
259→    /// Estimated number of calls based on static call-site count.
260→    pub call_count_estimate: u32,
261→    /// Where the mock's return value came from.
262→    pub value_source: ValueSource,
263→}
264→
265→/// Build [`MockParam`]s from dependencies and their resolved mock configs.
266→///
267→/// Filters out dependencies whose category is [`IoCategory::PureUtility`]
268→/// unless a matching config explicitly overrides them. Dependencies with
269→/// a matching config get [`ValueSource::UserOverride`]; those without get
270→/// [`ValueSource::AutoGenerated`].
271→pub fn build_mock_params(
272→    deps: &[ExternalDependency],
273→    configs: &[MockConfig],
274→) -> Vec<MockParam> {
275→    let config_by_symbol: HashMap<&str, &MockConfig> = configs
276→        .iter()
277→        .map(|c| (c.symbol.as_str(), c))
278→        .collect();
279→
280→    let mut result = Vec::new();
281→
282→    for dep in deps {
283→        let category = classify_dependency(dep);
284→        let has_config = config_by_symbol.contains_key(dep.symbol.as_str());
285→
286→        // Pure utilities are passthrough unless explicitly configured
287→        if category == IoCategory::PureUtility && !has_config {
288→            continue;
289→        }
290→
291→        let value_source = if has_config {
292→            ValueSource::UserOverride
293→        } else {
294→            ValueSource::AutoGenerated
295→        };
296→
297→        result.push(MockParam {
298→            symbol: dep.symbol.clone(),
299→            return_type: dep.return_type.clone(),
300→            category,
301→            call_count_estimate: dep.call_sites.len() as u32,
302→            value_source,
303→        });
304→    }
305→
306→    result
307→}
