179→/// Generate auto-mocks for all dependencies of a function.
180→///
181→/// Returns mock configs for dependencies that:
182→/// 1. Are not already covered by `existing_mocks` (e.g., behavior-map mocks)
183→/// 2. Are classified as Mock (not Passthrough or Analyze) by the scope matcher
184→///
185→/// User overrides from config take precedence over auto-generated defaults.
186→pub fn generate_auto_mocks(
187→    deps: &[ExternalDependency],
188→    scope: Option<&ScopeMatcher>,
189→    overrides: &HashMap<String, MockOverride>,
190→    existing_mocks: &[MockConfig],
191→) -> Vec<MockConfig> {
192→    let already_mocked: std::collections::HashSet<&str> = existing_mocks
193→        .iter()
194→        .map(|m| m.symbol.as_str())
195→        .collect();
196→
197→    let mut result = Vec::new();
198→
199→    for dep in deps {
200→        // Skip if already covered by a behavior-map mock
201→        if already_mocked.contains(dep.symbol.as_str()) {
202→            continue;
203→        }
204→
205→        // Check scope: if Passthrough, skip; if Analyze (no rule), use category logic
206→        if let Some(matcher) = scope {
207→            match matcher.classify_dependency(&dep.symbol) {
208→                DependencyAction::Passthrough => continue,
209→                DependencyAction::Mock | DependencyAction::Analyze => {}
210→            }
211→        }
212→
213→        let category = classify_dependency(dep);
214→
215→        // Pure utilities default to passthrough — skip generating a mock
216→        if category == IoCategory::PureUtility && !overrides.contains_key(&dep.symbol) {
217→            continue;
218→        }
219→
220→        let mut mock = generate_default_mock(dep, category);
221→
222→        // Apply user overrides
223→        if let Some(ov) = overrides.get(&dep.symbol) {
224→            if let Some(ref vals) = ov.return_values {
225→                mock.return_values = vals.clone();
226→            }
227→            if let Some(ref behavior) = ov.behavior {
228→                mock.default_behavior = behavior.clone();
229→            }
230→        }
231→
232→        result.push(mock);
233→    }
234→
235→    result
236→}
237→
238→/// Where a mock's return value originated.
239→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
240→pub enum ValueSource {
241→    /// Generated automatically from dependency classification and type info.
242→    AutoGenerated,
243→    /// Overridden by the user via `.shatter/config.yaml`.
244→    UserOverride,
245→    /// Inherited from an existing behavior-map mock.
246→    BehaviorMap,
247→}
248→
249→/// A resolved mock parameter ready for the orchestrator, combining dependency
250→/// metadata with its mock configuration.
251→#[derive(Debug, Clone, PartialEq)]
252→pub struct MockParam {
253→    /// Fully qualified symbol name of the mocked dependency.
254→    pub symbol: String,
255→    /// Return type of the dependency (used for value generation).
256→    pub return_type: TypeInfo,
257→    /// Classified I/O category.
258→    pub category: IoCategory,
259→    /// Estimated number of calls based on static call-site count.
260→    pub call_count_estimate: u32,
261→    /// Where the mock's return value came from.
262→    pub value_source: ValueSource,
263→}
264→
265→/// Build [`MockParam`]s from dependencies and their resolved mock configs.
266→///
267→/// Filters out dependencies whose category is [`IoCategory::PureUtility`]
268→/// unless a matching config explicitly overrides them. Dependencies with
269→/// a matching config get [`ValueSource::UserOverride`]; those without get
270→/// [`ValueSource::AutoGenerated`].
271→pub fn build_mock_params(
272→    deps: &[ExternalDependency],
273→    configs: &[MockConfig],
274→) -> Vec<MockParam> {
275→    let config_by_symbol: HashMap<&str, &MockConfig> = configs
276→        .iter()
277→        .map(|c| (c.symbol.as_str(), c))
278→        .collect();
279→
280→    let mut result = Vec::new();
281→
282→    for dep in deps {
283→        let category = classify_dependency(dep);
284→        let has_config = config_by_symbol.contains_key(dep.symbol.as_str());
285→
286→        // Pure utilities are passthrough unless explicitly configured
287→        if category == IoCategory::PureUtility && !has_config {
288→            continue;
289→        }
290→
291→        let value_source = if has_config {
292→            ValueSource::UserOverride
293→        } else {
294→            ValueSource::AutoGenerated
295→        };
296→
297→        result.push(MockParam {
298→            symbol: dep.symbol.clone(),
299→            return_type: dep.return_type.clone(),
300→            category,
301→            call_count_estimate: dep.call_sites.len() as u32,
302→            value_source,
303→        });
304→    }
305→
306→    result
307→}
