                novel_count,
                first_novel_depth,
            }),
        Just(TriageVerdict::Indeterminate),
    ]
}

pub fn arb_triage_disable_reason() -> impl Strategy<Value = TriageDisableReason> {
    prop_oneof![
        Just(TriageDisableReason::LowSkipRate),
        Just(TriageDisableReason::HighMisprediction),
    ]
}

