278→
279→    // -- Branching function: two conditions --
280→
281→    #[test]
282→    fn branching_function_produces_two_conditions() {
283→        let map = make_behavior_map(
284→            "classify",
285→            vec![
286→                make_behavior(0, vec![json!(5)], Some(json!("positive")), None),
287→                make_behavior(1, vec![json!(-3)], Some(json!("negative")), None),
288→            ],
289→        );
290→
