        let tree = build_mock_from_behavior_map(&map).expect("should produce a tree");
        // Only the second behavior produced a condition
        assert_eq!(tree.conditions.len(), 1);
        assert_eq!(tree.conditions[0].return_value, json!("ok"));
    }
