/// Generate a Color value (RGBA).
fn generate_color(rng: &mut impl Rng) -> Value {
    let choice: u8 = rng.random_range(0..5);
    let (r, g, b, a) = match choice {
        0 => (0, 0, 0, 255),         // black
        1 => (255, 255, 255, 255),   // white
        2 => (255, 0, 0, 255),       // red
        3 => (0, 0, 0, 0),           // transparent
        _ => (
            rng.random_range(0..=255),
