        let mut saw_max = false;
        for _ in 0..500 {
            let mutated = mutate_value(&json!(42), &TypeInfo::Int, &[], &mut rng);
            let n = mutated.as_i64().or_else(|| mutated.as_u64().map(|u| u as i64));
            if let Some(n) = n {
