        #[test]
        fn crossover_mock_values_preserves_structure() {
            let mut rng = seeded_rng();
            let params = vec![
                make_mock_param("f1", TypeInfo::Int, IoCategory::ExternalOther, 2),
                make_mock_param("f2", TypeInfo::Str, IoCategory::ExternalOther, 1),
            ];
            let parent_a = generate_mock_values(&params, &mut rng, None);
            let parent_b = generate_mock_values(&params, &mut rng, None);

            let (child1, child2) =
                crossover_mock_values(&parent_a, &parent_b, &params, 1.0, &mut rng);

            assert_eq!(child1.len(), parent_a.len());
            assert_eq!(child2.len(), parent_b.len());
            assert_eq!(child1[0].symbol, parent_a[0].symbol);
            assert_eq!(child1[1].symbol, parent_a[1].symbol);
            assert_eq!(child2[0].symbol, parent_b[0].symbol);
            assert_eq!(child2[1].symbol, parent_b[1].symbol);
        }

        #[test]
        fn crossover_mock_values_zero_rate_clones_parents() {
            let mut rng = seeded_rng();
            let params = vec![make_mock_param("f1", TypeInfo::Int, IoCategory::ExternalOther, 2)];
            let parent_a = generate_mock_values(&params, &mut rng, None);
            let parent_b = generate_mock_values(&params, &mut rng, None);

            let (child1, child2) =
                crossover_mock_values(&parent_a, &parent_b, &params, 0.0, &mut rng);

            assert_eq!(child1, parent_a);
            assert_eq!(child2, parent_b);
        }

        #[test]
        fn crossover_mock_values_unequal_return_value_lengths() {
            let mut rng = seeded_rng();
            let params = vec![make_mock_param("f1", TypeInfo::Int, IoCategory::ExternalOther, 1)];

            let mut config_a = generate_mock_values(&params, &mut rng, None);
            config_a[0].return_values.push(json!(99)); // extra value

            let config_b = generate_mock_values(&params, &mut rng, None);

            let (child1, child2) =
                crossover_mock_values(&config_a, &config_b, &params, 1.0, &mut rng);

            // child1 should have the extra trailing element from parent_a
            assert!(child1[0].return_values.len() >= config_b[0].return_values.len());
            assert!(child2[0].return_values.len() >= config_b[0].return_values.len());
        }
    }

    // -----------------------------------------------------------------------
    // Mock value generation proptest
    // -----------------------------------------------------------------------

    mod mock_gen_proptests {
        use super::*;
        use crate::auto_mock::{IoCategory, MockParam, ValueSource};
        use proptest::prelude::*;

        fn arb_io_category() -> impl Strategy<Value = IoCategory> {
            prop_oneof![
                Just(IoCategory::FileSystem),
                Just(IoCategory::Network),
                Just(IoCategory::Database),
                Just(IoCategory::PureUtility),
                Just(IoCategory::ExternalOther),
            ]
        }

        fn arb_value_source() -> impl Strategy<Value = ValueSource> {
            prop_oneof![
                Just(ValueSource::AutoGenerated),
                Just(ValueSource::UserOverride),
                Just(ValueSource::BehaviorMap),
            ]
        }

        fn arb_mock_param() -> impl Strategy<Value = MockParam> {
            (
                "[a-zA-Z_][a-zA-Z0-9_]{0,12}",
                crate::test_arbitraries::arb_type_info(1),
                arb_io_category(),
                0..5u32,
                arb_value_source(),
            )
                .prop_map(
                    |(symbol, return_type, category, call_count_estimate, value_source)| {
                        MockParam {
                            symbol,
                            return_type,
                            category,
                            call_count_estimate,
                            value_source,
                        }
                    },
                )
        }

        proptest! {
            /// generate_mock_values produces one MockConfig per MockParam,
            /// with the correct symbol and at least 1 return value.
            #[test]
            fn generate_produces_correct_structure(
                seed in any::<u64>(),
                params in prop::collection::vec(arb_mock_param(), 0..=5),
            ) {
                let mut rng = StdRng::seed_from_u64(seed);
                let configs = generate_mock_values(&params, &mut rng, None);

                prop_assert_eq!(configs.len(), params.len());
                for (config, mp) in configs.iter().zip(params.iter()) {
                    prop_assert_eq!(&config.symbol, &mp.symbol);
                    prop_assert!(
                        !config.return_values.is_empty(),
                        "MockConfig for {} should have at least 1 return value",
                        mp.symbol
                    );
                    prop_assert!(config.should_track_calls);
                }
            }

            /// mutate_mock_values preserves symbol, return value count, and structure.
            #[test]
            fn mutate_preserves_type_contracts(
                seed in any::<u64>(),
                params in prop::collection::vec(arb_mock_param(), 1..=3),
                mutation_rate in 0.0..=1.0_f64,
            ) {
                let mut rng = StdRng::seed_from_u64(seed);
                let configs = generate_mock_values(&params, &mut rng, None);
                let mutated = mutate_mock_values(&configs, &params, mutation_rate, &[], &mut rng);

                prop_assert_eq!(mutated.len(), configs.len());
                for (m, c) in mutated.iter().zip(configs.iter()) {
                    prop_assert_eq!(&m.symbol, &c.symbol);
                    prop_assert_eq!(m.return_values.len(), c.return_values.len());
                    prop_assert_eq!(&m.default_behavior, &c.default_behavior);
                }
            }

            /// crossover_mock_values preserves vector structure (length, symbols).
            #[test]
            fn crossover_preserves_vector_structure(
                seed in any::<u64>(),
                params in prop::collection::vec(arb_mock_param(), 1..=3),
                crossover_rate in 0.0..=1.0_f64,
            ) {
                let mut rng = StdRng::seed_from_u64(seed);
                let parent_a = generate_mock_values(&params, &mut rng, None);
                let parent_b = generate_mock_values(&params, &mut rng, None);

                let (child1, child2) = crossover_mock_values(
                    &parent_a, &parent_b, &params, crossover_rate, &mut rng,
                );

                let expected_len = parent_a.len().min(parent_b.len()).min(params.len());
                prop_assert_eq!(child1.len(), expected_len);
                prop_assert_eq!(child2.len(), expected_len);

                for i in 0..expected_len {
                    prop_assert_eq!(&child1[i].symbol, &parent_a[i].symbol);
                    prop_assert_eq!(&child2[i].symbol, &parent_b[i].symbol);
                }
            }
        }
    }
}

