            type_name: None,
        }];
        let parent_a = vec![json!({"x": 1, "y": 2, "z": 3})];
        let parent_b = vec![json!({"x": 10, "y": 20, "z": 30})];

        let mut saw_field_mix = false;
        for seed in 0..100_u64 {
