                let parent_b: Vec<serde_json::Value> = params
                    .iter()
                    .map(|p| generate_random_value(&p.typ, &mut rng, None))
                    .collect();

                let mut rng2 = StdRng::seed_from_u64(seed.wrapping_add(1));
                let (child1, child2) = crossover_inputs(
