            let config_b = generate_mock_values(&params, &mut rng, None);

            let (child1, child2) =
                crossover_mock_values(&config_a, &config_b, &params, 1.0, &mut rng);

            // child1 should have the extra trailing element from parent_a
            assert!(child1[0].return_values.len() >= config_b[0].return_values.len());
            assert!(child2[0].return_values.len() >= config_b[0].return_values.len());
        }
