/// Generate return values for a single mock, handling error types and category shaping.
fn generate_mock_return_values(
    return_type: &TypeInfo,
    category: IoCategory,
    count: usize,
    rng: &mut impl Rng,
    caps: Option<&FrontendCapabilities>,
) -> (Vec<Value>, MockBehavior) {
    // Check for declared error types that should produce both success and error variants.
    if is_result_type(return_type) {
        let mut values = Vec::with_capacity(count + 1);
        // Generate success variants for most slots, one error variant
        for _ in 0..count {
            values.push(generate_random_value(return_type, rng, caps));
        }
        // Add an explicit error variant
        values.push(json!({"error": "mock error", "message": "simulated failure"}));
        return (values, MockBehavior::ReturnGenerated);
    }

    if let Some(error_idx) = union_error_variant_index(return_type)
        && let TypeInfo::Union { variants } = return_type
    {
        let mut values = Vec::with_capacity(count + 1);
        // Generate values from non-error variants
        for _ in 0..count {
            let non_error_idx = pick_non_error_variant(variants.len(), error_idx, rng);
            values.push(generate_random_value(&variants[non_error_idx], rng, caps));
        }
        // Add an error variant
        values.push(generate_random_value(&variants[error_idx], rng, caps));
        return (values, MockBehavior::ReturnGenerated);
    }

    // Category-aware shaping for Unknown return types
    if matches!(return_type, TypeInfo::Unknown) {
        let values = (0..count)
            .map(|_| category_shaped_value(category, rng))
            .collect();
        return (values, MockBehavior::RepeatLast);
    }

    // Standard type-driven generation
    let values = (0..count)
        .map(|_| generate_random_value(return_type, rng, caps))
        .collect();
    (values, MockBehavior::RepeatLast)
}

