/// Generate return values for a single mock, handling error types and category shaping.
///
/// For Result types, calls `generate_result()` directly (produces both ok/err
/// variants without requiring frontend capabilities). For unions containing
/// an Error variant, reserves at least one slot for the error variant and
/// generates success variants from the remaining union members.
fn generate_mock_return_values(
    return_type: &TypeInfo,
    category: IoCategory,
    count: usize,
    rng: &mut impl Rng,
    caps: Option<&FrontendCapabilities>,
) -> (Vec<Value>, MockBehavior) {
    // Result types: generate_result() already mixes ok/err variants (30% err).
    if is_result_type(return_type) {
        let values = (0..count).map(|_| generate_result(rng)).collect();
        return (values, MockBehavior::ReturnGenerated);
    }

    // Union-with-Error: reserve slots for both success and error variants.
    if let Some(error_idx) = union_error_variant_index(return_type)
        && let TypeInfo::Union { variants } = return_type
    {
        let mut values = Vec::with_capacity(count);
        if count >= 2 {
            // Reserve one slot for the error variant
            let error_metadata = match &variants[error_idx] {
                TypeInfo::Complex { metadata, .. } => metadata,
                _ => &serde_json::Map::new(),
            };
            for i in 0..count {
                if i == count - 1 {
                    // Last slot: generate an error variant directly
                    values.push(generate_error(error_metadata, rng));
                } else {
                    // Other slots: generate from non-error variants
                    let idx = pick_non_error_variant(variants.len(), error_idx, rng);
                    values.push(generate_random_value(&variants[idx], rng, caps));
                }
            }
        } else {
            // Only 1 slot: use normal union generation
            values.push(generate_union(variants, rng, caps));
        }
        return (values, MockBehavior::ReturnGenerated);
    }

    // Category-aware shaping for Unknown return types
    if matches!(return_type, TypeInfo::Unknown) {
        let values = (0..count)
            .map(|_| category_shaped_value(category, rng))
            .collect();
        return (values, MockBehavior::RepeatLast);
    }

    // Standard type-driven generation
    let values = (0..count)
        .map(|_| generate_random_value(return_type, rng, caps))
        .collect();
    (values, MockBehavior::RepeatLast)
}

