/// Generate a Locale value.
fn generate_locale(rng: &mut impl Rng) -> Value {
    let locales = ["en-US", "zh-CN", "ar-SA", "ja-JP", "de-DE", "invalid"];
    let idx = rng.random_range(0..locales.len());
