            fn mutate_bool_preserves_bool(val in any::<bool>()) {
                let input = serde_json::json!(val);
                let result = mutate_value(&input, &TypeInfo::Bool, &[], &mut StdRng::seed_from_u64(42));
                prop_assert!(
                    result.is_boolean(),
                    "mutating Bool produced non-bool: {result:?}"
                );
